    30→export function SubscriptionProvider({ children }) {
    31→  const { currentUser, userProfile, refreshUserProfile } = useAuth();
    32→  const [subscription, setSubscription] = useState('free');
    33→  const [usageCount, setUsageCount] = useState(0);
    34→  const [checkingSubscription, setCheckingSubscription] = useState(true);
    35→
    36→  useEffect(() => {
    37→    if (userProfile) {
    38→      setSubscription(userProfile.subscription || 'free');
    39→      setUsageCount(userProfile.usageCount || 0);
    40→      setCheckingSubscription(false);
    41→    } else {
    42→      setCheckingSubscription(false);
    43→    }
    44→  }, [userProfile]);
    45→
    46→  function canUseTool(categoryId) {
    47→    if (!currentUser) return false;
    48→    const plan = PLANS[subscription] || PLANS.free;
    49→    if (!plan.categories.includes(categoryId)) return false;
    50→    if (plan.dailyLimit !== Infinity && usageCount >= plan.dailyLimit) return false;
    51→    return true;
    52→  }
    53→
    54→  function isCategoryLocked(categoryId) {
    55→    const plan = PLANS[subscription] || PLANS.free;
    56→    return !plan.categories.includes(categoryId);
    57→  }
    58→
    59→  async function trackUsage() {
    60→    if (!currentUser) return;
