    66→      console.error('Error tracking usage:', err);
    67→    }
    68→  }
    69→
    70→  function getPlanLimits() {
    71→    return PLANS[subscription] || PLANS.free;
    72→  }
    73→
    74→  function isAtLimit() {
    75→    const plan = PLANS[subscription] || PLANS.free;
    76→    return plan.dailyLimit !== Infinity && usageCount >= plan.dailyLimit;
    77→  }
    78→
    79→  const value = {
