    82→    checkingSubscription,
    83→    canUseTool,
    84→    isCategoryLocked,
    85→    trackUsage,
    86→    getPlanLimits,
    87→    isAtLimit,
    88→    PLANS,
    89→    refreshUserProfile,
    90→  };
    91→
    92→  return (
